using sv_1149658f7b824f6997dffc7f50c89489.Models;

namespace sv_1149658f7b824f6997dffc7f50c89489.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

using sv_1149658f7b824f6997dffc7f50c89489.Models;

namespace sv_1149658f7b824f6997dffc7f50c89489.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 25),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with egg, pecorino, and guanciale.", 20),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 30),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", 35),
            new(5, "Green Curry", "Coconut milk curry with Thai basil and vegetables.", 40),
            new(6, "Tom Yum Soup", "Spicy and sour soup with lemongrass and galangal.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 45),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough pastries coated in cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

